(() => {
  const pollingHandles = new Map();
  const detailsKeyPrefix = "colin:details:";
  const refreshStateKey = "colin:auto-refresh";
  const refreshToggleSelector = "[data-refresh-toggle]";
  const localTimeSelector = "[data-local-time][data-timestamp]";

  function findHXTargets(root) {
    return Array.from(root.querySelectorAll("[hx-get]")).filter((element) => !element.dataset.hxBound);
  }

  function preserveDetailsState(root) {
    Array.from(root.querySelectorAll("details[data-preserve-open]")).forEach((element) => {
      if (!element.id || element.dataset.detailsBound) {
        return;
      }
      const state = sessionStorage.getItem(detailsKeyPrefix + element.id);
      if (state === "open") {
        element.open = true;
      }
      element.addEventListener("toggle", () => {
        sessionStorage.setItem(detailsKeyPrefix + element.id, element.open ? "open" : "closed");
      });
      element.dataset.detailsBound = "true";
    });
  }

  function requestFragment(element, event) {
    const targetSelector = element.getAttribute("hx-target");
    const target = targetSelector ? document.querySelector(targetSelector) : element;
    const swapMode = (element.getAttribute("hx-swap") || "innerHTML").toLowerCase();
    if (!target) {
      return Promise.resolve();
    }

    return fetch(element.getAttribute("hx-get"), {
      headers: { "HX-Request": "true" },
    })
      .then((response) => response.text())
      .then((html) => {
        if (swapMode === "outerhtml") {
          target.outerHTML = html;
        } else {
          target.innerHTML = html;
        }
        if (event) {
          event.preventDefault();
        }
        setTimeout(() => initialize(document), 0);
      });
  }

  function allowsClickTrigger(element) {
    const triggers = (element.getAttribute("hx-trigger") || "")
      .split(",")
      .map((value) => value.trim())
      .filter(Boolean);
    return triggers.length === 0 || triggers.includes("click");
  }

  function bindHXClicks(root) {
    findHXTargets(root).forEach((element) => {
      element.dataset.hxBound = "true";
      if (!allowsClickTrigger(element)) {
        return;
      }
      element.addEventListener("click", (event) => {
        event.preventDefault();
        requestFragment(element, event);
      });
    });
  }

  function clearPolling() {
    pollingHandles.forEach((handle) => clearInterval(handle));
    pollingHandles.clear();
  }

  function autoRefreshPaused() {
    return sessionStorage.getItem(refreshStateKey) === "paused";
  }

  function setAutoRefreshPaused(paused) {
    sessionStorage.setItem(refreshStateKey, paused ? "paused" : "running");
  }

  function pollingKey(element) {
    return element.id || element.getAttribute("hx-target") || element.getAttribute("hx-get");
  }

  function bindPolling(root) {
    clearPolling();
    if (autoRefreshPaused()) {
      return;
    }

    Array.from(root.querySelectorAll("[hx-trigger]")).forEach((element) => {
      const triggers = (element.getAttribute("hx-trigger") || "").split(",").map((value) => value.trim());
      triggers.forEach((trigger) => {
        const match = trigger.match(/^every\s+(\d+(?:\.\d+)?)s$/);
        if (!match) {
          return;
        }
        const key = pollingKey(element);
        const handle = setInterval(() => requestFragment(element), Number(match[1]) * 1000);
        if (key) {
          pollingHandles.set(key, handle);
        }
      });
    });
  }

  function applyRefreshToggle(root) {
    Array.from(root.querySelectorAll(refreshToggleSelector)).forEach((button) => {
      if (!button.dataset.toggleBound) {
        button.addEventListener("click", (event) => {
          event.preventDefault();
          const paused = !autoRefreshPaused();
          setAutoRefreshPaused(paused);
          updateRefreshToggle(document);
          bindPolling(document);
          if (!paused) {
            const dashboard = document.querySelector("#dashboard-root");
            if (dashboard) {
              requestFragment(dashboard);
            }
          }
        });
        button.dataset.toggleBound = "true";
      }
    });
    updateRefreshToggle(root);
  }

  function updateRefreshToggle(root) {
    const paused = autoRefreshPaused();
    Array.from(root.querySelectorAll(refreshToggleSelector)).forEach((button) => {
      button.textContent = paused ? "▶" : "❚❚";
      button.setAttribute("aria-label", paused ? "Resume automatic refresh" : "Pause automatic refresh");
      button.setAttribute("title", paused ? "Resume automatic refresh" : "Pause automatic refresh");
      button.setAttribute("aria-pressed", paused ? "true" : "false");
    });
  }

  function applyLocalTimes(root) {
    const formatter = new Intl.DateTimeFormat(undefined, {
      hour: "2-digit",
      minute: "2-digit",
      second: "2-digit",
      timeZoneName: "short",
    });

    Array.from(root.querySelectorAll(localTimeSelector)).forEach((element) => {
      const timestamp = element.getAttribute("data-timestamp");
      if (!timestamp) {
        return;
      }
      const value = new Date(timestamp);
      if (Number.isNaN(value.getTime())) {
        return;
      }
      element.textContent = formatter.format(value);
    });
  }

  function initialize(root) {
    bindHXClicks(root);
    bindPolling(document);
    preserveDetailsState(root);
    applyRefreshToggle(root);
    applyLocalTimes(root);
  }

  document.addEventListener("DOMContentLoaded", () => initialize(document));
})();
